/// @file neon_fp32_4x8.cpp
/// Auto-generated packed 4x8 FP32 NEON micro-kernel.
/// Generated by: tools/gen_neon_gemm.py
///   Mr=4, Nr=8, K_unroll=4
///   Register budget: 8 acc + 2 B + 1 A = 11 regs
///   1-pass (fits in 32 regs)

