// ============================================================
// Pack A: 4 contiguous floats per K
// ============================================================

static void pack_a_fp32_4x8(
        int m_len, int k_len,
        const float* A, int lda,
        float* packed_A) {
    constexpr int Mr = 4;
    for (int i = 0; i < m_len; i += Mr) {
        int m_rem = std::min(Mr, m_len - i);
        if (m_rem == Mr) {
            for (int k = 0; k < k_len; ++k) {
                packed_A[0] = A[(i + 0) * lda + k];
                packed_A[1] = A[(i + 1) * lda + k];
                packed_A[2] = A[(i + 2) * lda + k];
                packed_A[3] = A[(i + 3) * lda + k];
                packed_A += 4;
            }
        } else {
            for (int k = 0; k < k_len; ++k) {
                int r = 0;
                for (; r < m_rem; ++r)
                    packed_A[r] = A[(i + r) * lda + k];
                for (; r < Mr; ++r)
                    packed_A[r] = 0.0f;
                packed_A += 4;
            }
        }
    }
}
// ============================================================
// Pack B: 8 contiguous floats per K (2 quads)
// ============================================================

static void pack_b_fp32_4x8(
        int k_len, int n_len,
        const float* B, int ldb,
        float* packed_B) {
    constexpr int Nr = 8;
    for (int j = 0; j < n_len; j += Nr) {
        int n_rem = std::min(Nr, n_len - j);
        if (n_rem == Nr) {
            for (int k = 0; k < k_len; ++k) {
                const float* src = &B[k * ldb + j];
                vst1q_f32(packed_B + 0, vld1q_f32(src + 0));
                vst1q_f32(packed_B + 4, vld1q_f32(src + 4));
                packed_B += Nr;
            }
        } else {
            for (int k = 0; k < k_len; ++k) {
                const float* src = &B[k * ldb + j];
                int c = 0;
                for (; c < n_rem; ++c)
                    packed_B[c] = src[c];
                for (; c < Nr; ++c)
                    packed_B[c] = 0.0f;
                packed_B += Nr;
            }
        }
    }
}
// ============================================================
// Packed 4x8 NEON micro-kernel (4x K-unrolled)
// ============================================================

static void gemm_ukernel_fp32_packed_4x8(
        int K,
        const float* __restrict__ packed_A,
        const float* __restrict__ packed_B,
        float* __restrict__ C, int ldc,
        float alpha, float beta) {

    float32x4_t a00 = vdupq_n_f32(0);
    float32x4_t a01 = vdupq_n_f32(0);
    float32x4_t a10 = vdupq_n_f32(0);
    float32x4_t a11 = vdupq_n_f32(0);
    float32x4_t a20 = vdupq_n_f32(0);
    float32x4_t a21 = vdupq_n_f32(0);
    float32x4_t a30 = vdupq_n_f32(0);
    float32x4_t a31 = vdupq_n_f32(0);

    const float* __restrict__ pA = packed_A;
    const float* __restrict__ pB = packed_B;

    // 4x K-unrolled main loop
    int k = 0;
    for (; k + 3 < K; k += 4) {
        if (k + 16 < K) {
            __asm__ volatile("prfm pldl1keep, [%0]" : : "r"(pA + 16) : "memory");
            __asm__ volatile("prfm pldl1keep, [%0]" : : "r"(pB + 32) : "memory");
        }

        // K iteration 0
        {
            float32x4_t ar0 = vld1q_f32(pA + 0);
            pA += 4;
            float32x4_t b0 = vld1q_f32(pB + 0);
            float32x4_t b1 = vld1q_f32(pB + 4);
            pB += 8;
            a00 = vfmaq_laneq_f32(a00, b0, ar0, 0);
            a01 = vfmaq_laneq_f32(a01, b1, ar0, 0);
            a10 = vfmaq_laneq_f32(a10, b0, ar0, 1);
            a11 = vfmaq_laneq_f32(a11, b1, ar0, 1);
            a20 = vfmaq_laneq_f32(a20, b0, ar0, 2);
            a21 = vfmaq_laneq_f32(a21, b1, ar0, 2);
            a30 = vfmaq_laneq_f32(a30, b0, ar0, 3);
            a31 = vfmaq_laneq_f32(a31, b1, ar0, 3);
        }

        // K iteration 1
        {
            float32x4_t ar0 = vld1q_f32(pA + 0);
            pA += 4;
            float32x4_t b0 = vld1q_f32(pB + 0);
            float32x4_t b1 = vld1q_f32(pB + 4);
            pB += 8;
            a00 = vfmaq_laneq_f32(a00, b0, ar0, 0);
            a01 = vfmaq_laneq_f32(a01, b1, ar0, 0);
            a10 = vfmaq_laneq_f32(a10, b0, ar0, 1);
            a11 = vfmaq_laneq_f32(a11, b1, ar0, 1);
            a20 = vfmaq_laneq_f32(a20, b0, ar0, 2);
            a21 = vfmaq_laneq_f32(a21, b1, ar0, 2);
            a30 = vfmaq_laneq_f32(a30, b0, ar0, 3);
            a31 = vfmaq_laneq_f32(a31, b1, ar0, 3);
        }

        // K iteration 2
        {
            float32x4_t ar0 = vld1q_f32(pA + 0);
            pA += 4;
            float32x4_t b0 = vld1q_f32(pB + 0);
            float32x4_t b1 = vld1q_f32(pB + 4);
            pB += 8;
            a00 = vfmaq_laneq_f32(a00, b0, ar0, 0);
            a01 = vfmaq_laneq_f32(a01, b1, ar0, 0);
            a10 = vfmaq_laneq_f32(a10, b0, ar0, 1);
            a11 = vfmaq_laneq_f32(a11, b1, ar0, 1);
            a20 = vfmaq_laneq_f32(a20, b0, ar0, 2);
            a21 = vfmaq_laneq_f32(a21, b1, ar0, 2);
            a30 = vfmaq_laneq_f32(a30, b0, ar0, 3);
            a31 = vfmaq_laneq_f32(a31, b1, ar0, 3);
        }

        // K iteration 3
        {
            float32x4_t ar0 = vld1q_f32(pA + 0);
            pA += 4;
            float32x4_t b0 = vld1q_f32(pB + 0);
            float32x4_t b1 = vld1q_f32(pB + 4);
            pB += 8;
            a00 = vfmaq_laneq_f32(a00, b0, ar0, 0);
            a01 = vfmaq_laneq_f32(a01, b1, ar0, 0);
            a10 = vfmaq_laneq_f32(a10, b0, ar0, 1);
            a11 = vfmaq_laneq_f32(a11, b1, ar0, 1);
            a20 = vfmaq_laneq_f32(a20, b0, ar0, 2);
            a21 = vfmaq_laneq_f32(a21, b1, ar0, 2);
            a30 = vfmaq_laneq_f32(a30, b0, ar0, 3);
            a31 = vfmaq_laneq_f32(a31, b1, ar0, 3);
        }
    }

    // K tail
    for (; k < K; ++k) {
        float32x4_t ar0 = vld1q_f32(pA + 0);
        pA += 4;
        float32x4_t b0 = vld1q_f32(pB + 0);
        float32x4_t b1 = vld1q_f32(pB + 4);
        pB += 8;
        a00 = vfmaq_laneq_f32(a00, b0, ar0, 0);
        a01 = vfmaq_laneq_f32(a01, b1, ar0, 0);
        a10 = vfmaq_laneq_f32(a10, b0, ar0, 1);
        a11 = vfmaq_laneq_f32(a11, b1, ar0, 1);
        a20 = vfmaq_laneq_f32(a20, b0, ar0, 2);
        a21 = vfmaq_laneq_f32(a21, b1, ar0, 2);
        a30 = vfmaq_laneq_f32(a30, b0, ar0, 3);
        a31 = vfmaq_laneq_f32(a31, b1, ar0, 3);
    }

    // Epilogue: store C = alpha * acc + beta * C
    float32x4_t av = vdupq_n_f32(alpha);
    float32x4_t bv = vdupq_n_f32(beta);
    {
        float* cr = C + 0 * ldc;
        if (beta == 0.0f) {
            vst1q_f32(cr, vmulq_f32(av, a00));
            vst1q_f32(cr + 4, vmulq_f32(av, a01));
        } else {
            vst1q_f32(cr, vfmaq_f32(vmulq_f32(av, a00), bv, vld1q_f32(cr)));
            vst1q_f32(cr + 4, vfmaq_f32(vmulq_f32(av, a01), bv, vld1q_f32(cr + 4)));
        }
    }
    {
        float* cr = C + 1 * ldc;
        if (beta == 0.0f) {
            vst1q_f32(cr, vmulq_f32(av, a10));
            vst1q_f32(cr + 4, vmulq_f32(av, a11));
        } else {
            vst1q_f32(cr, vfmaq_f32(vmulq_f32(av, a10), bv, vld1q_f32(cr)));
            vst1q_f32(cr + 4, vfmaq_f32(vmulq_f32(av, a11), bv, vld1q_f32(cr + 4)));
        }
    }
    {
        float* cr = C + 2 * ldc;
        if (beta == 0.0f) {
            vst1q_f32(cr, vmulq_f32(av, a20));
            vst1q_f32(cr + 4, vmulq_f32(av, a21));
        } else {
            vst1q_f32(cr, vfmaq_f32(vmulq_f32(av, a20), bv, vld1q_f32(cr)));
            vst1q_f32(cr + 4, vfmaq_f32(vmulq_f32(av, a21), bv, vld1q_f32(cr + 4)));
        }
    }
    {
        float* cr = C + 3 * ldc;
        if (beta == 0.0f) {
            vst1q_f32(cr, vmulq_f32(av, a30));
            vst1q_f32(cr + 4, vmulq_f32(av, a31));
        } else {
            vst1q_f32(cr, vfmaq_f32(vmulq_f32(av, a30), bv, vld1q_f32(cr)));
            vst1q_f32(cr + 4, vfmaq_f32(vmulq_f32(av, a31), bv, vld1q_f32(cr + 4)));
        }
    }
}
// ============================================================
// Registry wrappers + auto-registration
